DELETE FROM user_relief_claims
WHERE user_tax_profile_id IN (
    SELECT id
    FROM user_tax_profile
    WHERE policy_year_id IN (
        SELECT id FROM policy_year WHERE year BETWEEN 2018 AND 2024
    )
);

DELETE FROM receipts
WHERE policy_year_id IN (
    SELECT id FROM policy_year WHERE year BETWEEN 2018 AND 2024
);

DELETE FROM user_tax_profile
WHERE policy_year_id IN (
    SELECT id FROM policy_year WHERE year BETWEEN 2018 AND 2024
);

DELETE FROM relief_categories
WHERE policy_year_id IN (
    SELECT id FROM policy_year WHERE year BETWEEN 2018 AND 2024
);

DELETE FROM tax_brackets
WHERE policy_year_id IN (
    SELECT id FROM policy_year WHERE year BETWEEN 2018 AND 2024
);

DELETE FROM ai_suggestions
WHERE policy_year_id IN (
    SELECT id FROM policy_year WHERE year BETWEEN 2018 AND 2024
);

