INSERT INTO tax_brackets (id, policy_year_id, min_income, max_income, tax_rate)
SELECT
    gen_random_uuid(),
    py.id,
    seed.min_income,
    seed.max_income,
    seed.tax_rate
FROM tax_bracket_seed seed
JOIN policy_year py ON py.year = seed.year;

