INSERT INTO relief_categories (
    id,
    policy_year_id,
    name,
    description,
    max_amount,
    type,
    requires_receipt,
    code,
    section,
    input_type,
    unit_amount,
    display_order,
    group_code,
    group_max_amount,
    exclusive_group_code,
    requires_category_code,
    auto_apply
)
SELECT
    gen_random_uuid(),
    py.id,
    seed.name,
    seed.description,
    seed.max_amount,
    seed.type,
    seed.requires_receipt,
    seed.code,
    seed.section,
    seed.input_type,
    seed.unit_amount,
    seed.display_order,
    seed.group_code,
    seed.group_max_amount,
    seed.exclusive_group_code,
    seed.requires_category_code,
    seed.auto_apply
FROM relief_seed seed
JOIN policy_year py ON py.year = seed.year;
